#!/usr/bin/env python3
"""
Mosferics Price List Generator
Version: 1.0.3
"""

# ── Version — increment this whenever you push an update ──────────────────
VERSION = "1.0.3"

# ── Update URL — replace with your GitHub raw file URL after setup ─────────
UPDATE_URL = "https://raw.githubusercontent.com/alt-ts/mosferics-tools/refs/heads/main/generate_price_list.py"

import os, sys, io, tempfile, datetime, base64, re
from pathlib import Path
 
# ── Embedded white logo ────────────────────────────────────────────────────
LOGO_B64 = ""
 
LIST_COLUMNS = ['Bar & Club', 'Bar & Casual Food', 'Cocktail Bar', 'Restaurant', 'Personalised']
 
# ── Auto-update ────────────────────────────────────────────────────────────
def check_for_update(silent=False):
    """
    Fetches the latest script from GitHub, compares version numbers,
    and if newer: saves the update and relaunches the program.
    Returns True if an update was applied (caller should exit).
    """
    import urllib.request, urllib.error
 
    # Don't update if running as a frozen PyInstaller exe during development
    # (comment out this block once you're happy with updates working)
 
    try:
        req = urllib.request.Request(
            UPDATE_URL,
            headers={'Cache-Control': 'no-cache', 'User-Agent': 'MosfericsUpdater/1.0'}
        )
        with urllib.request.urlopen(req, timeout=5) as resp:
            remote_src = resp.read().decode('utf-8')
    except Exception:
        # No internet or URL not set up yet — silently continue
        return False
 
    # Extract remote version
    match = re.search(r'^VERSION\s*=\s*["\']([^"\']+)["\']', remote_src, re.MULTILINE)
    if not match:
        return False
 
    remote_ver = match.group(1)
 
    def ver_tuple(v):
        try:
            return tuple(int(x) for x in v.split('.'))
        except ValueError:
            return (0,)
 
    if ver_tuple(remote_ver) <= ver_tuple(VERSION):
        return False  # Already up to date
 
    # Newer version available — ask user
    import tkinter as tk
    from tkinter import messagebox
    root = tk.Tk()
    root.withdraw()
 
    if not messagebox.askyesno(
        'Update Available',
        f'A new version is available (v{remote_ver}).\n\n'
        f'You are currently on v{VERSION}.\n\n'
        'Update now? The app will restart automatically.'
    ):
        root.destroy()
        return False
 
    root.destroy()
 
    # Save the new script alongside the current executable/script
    if getattr(sys, 'frozen', False):
        # Running as PyInstaller executable
        current_path = Path(sys.executable)
    else:
        # Running as .py script
        current_path = Path(__file__)
 
    # Write to a temp file first, then atomically replace the current script
    tmp_update = current_path.with_suffix('.tmp_update.py')
    try:
        tmp_update.write_text(remote_src, encoding='utf-8')
    except Exception as e:
        import tkinter as tk
        from tkinter import messagebox
        r = tk.Tk(); r.withdraw()
        messagebox.showerror('Update failed', f'Could not save update:\n{e}')
        r.destroy()
        return False
 
    # Replace current script with updated version
    try:
        # On Windows, can't replace a running file directly — rename current first
        import subprocess
        backup = current_path.with_suffix('.backup.py')
        if backup.exists():
            backup.unlink()
        current_path.rename(backup)
        tmp_update.rename(current_path)
        # Clean up backup
        try: backup.unlink()
        except: pass
    except Exception as e:
        # Rename failed — try direct overwrite
        try:
            current_path.write_text(remote_src, encoding='utf-8')
            tmp_update.unlink(missing_ok=True)
        except Exception:
            pass
 
    # Relaunch the updated script
    import subprocess
    try:
        subprocess.Popen([sys.executable, str(current_path)])
        return True
    except Exception:
        return False
 
# ── Logo loader ────────────────────────────────────────────────────────────
def get_logo_reader():
    from reportlab.lib.utils import ImageReader
    data = base64.b64decode(LOGO_B64)
    return ImageReader(io.BytesIO(data))
 
# ── Data loader ────────────────────────────────────────────────────────────
def load_products(excel_path, list_name):
    import openpyxl
    wb = openpyxl.load_workbook(excel_path, data_only=True)
    ws = wb.active
    headers = [cell.value for cell in next(ws.iter_rows())]
 
    if list_name not in headers:
        raise ValueError(f"Column '{list_name}' not found in the Excel file.")
 
    products, seen = [], set()
    for row in ws.iter_rows(min_row=2, values_only=True):
        d = dict(zip(headers, row))
        if not d.get(list_name):
            continue
        cat = str(d.get('Price File Category') or '').strip()
        if not cat or cat.lower() == 'none':
            continue
        title = str(d.get('Title') or '').strip()
        sku   = str(d.get('Variant SKU') or '').strip()
        price = d.get('Variant Price')
        if not title or not sku or price is None:
            continue
        if sku in seen:
            continue
        seen.add(sku)
        try:
            price = float(price)
        except (TypeError, ValueError):
            continue
        cat = cat.replace('Dipsoables', 'Disposables')
        products.append({'category': cat, 'title': title, 'sku': sku, 'price': price})
 
    if not products:
        raise ValueError(
            f"No products found for '{list_name}'.\n\n"
            "Check that TRUE is in the correct column for at least one product "
            "and that 'Price File Category' is filled in for those products."
        )
 
    grouped = {}
    for p in products:
        grouped.setdefault(p['category'], []).append(p)
    for cat in grouped:
        grouped[cat].sort(key=lambda x: x['title'])
    return dict(sorted(grouped.items()))
 
# ── PDF generator ──────────────────────────────────────────────────────────
def generate_pdf(grouped_products, list_name, output_path):
    from reportlab.lib.pagesizes import A4
    from reportlab.lib import colors
    from reportlab.lib.units import mm
    from reportlab.pdfgen import canvas
    from pypdf import PdfWriter, PdfReader
 
    W, H = A4
    ml, mr = 18*mm, 18*mm
    F, FB, FS = 'Helvetica', 'Helvetica-Bold', 7.0
    LH, RH, CH = 3.8*mm, 8*mm, 7.5*mm
    HDR = 28*mm + 2.5*mm + 8*mm
    FTR, NH = 14*mm, 9*mm
    NB = NH + 10*mm
 
    def hx(h): return colors.HexColor(h)
 
    logo_img = get_logo_reader()
 
    sku_w, price_w, gap = 26*mm, 28*mm, 2*mm
    name_w  = W - ml - mr - sku_w - gap - price_w - gap
    sku_x   = ml
    name_x  = sku_x + sku_w + gap
    price_x = name_x + name_w + gap
 
    def wrap(ref_c, text, max_w):
        words = str(text).split()
        lines, cur = [], ''
        for w in words:
            test = (cur + ' ' + w).strip()
            if ref_c.stringWidth(test, F, FS) <= max_w:
                cur = test
            else:
                if cur: lines.append(cur)
                cur = w
        if cur: lines.append(cur)
        return lines or [str(text)]
 
    def row_h(lines): return max(RH, len(lines) * LH + 4*mm)
 
    tmp0 = tempfile.mktemp(suffix='.pdf')
    ref  = canvas.Canvas(tmp0, pagesize=A4)
    ref.setFont(F, FS)
 
    all_items = []
    for cat, prods in grouped_products.items():
        all_items.append(('cat', cat))
        for p in prods:
            lines = wrap(ref, p['title'], name_w)
            all_items.append(('row', p['sku'], p['title'], p['price'], lines, row_h(lines)))
 
    avail_n = H - HDR - FTR - 4*mm
    avail_l = H - HDR - FTR - NB - 4*mm
    pages, cur_pg, used = [], [], 0.0
    for it in all_items:
        h = CH if it[0]=='cat' else it[5]
        if used + h > avail_n and cur_pg:
            pages.append(cur_pg); cur_pg=[]; used=0.0
        cur_pg.append(it); used += h
    if cur_pg: pages.append(cur_pg)
    total = len(pages)
 
    last_used = sum(CH if i[0]=='cat' else i[5] for i in pages[-1])
    if last_used > avail_l:
        overflow = []
        while pages[-1] and sum(CH if i[0]=='cat' else i[5] for i in pages[-1]) > avail_l:
            overflow.insert(0, pages[-1].pop())
        if overflow: pages.append(overflow); total = len(pages)
 
    page_files, row_idx = [], 0
 
    for pg_num, pg_items in enumerate(pages, 1):
        is_last = (pg_num == total)
        tmp = tempfile.mktemp(suffix='.pdf')
        page_files.append(tmp)
        c = canvas.Canvas(tmp, pagesize=A4)
 
        c.setFillColor(hx('#f5f5f5'))
        c.rect(0, 0, W, H, fill=1, stroke=0)
 
        c.setFillColor(hx('#1a1a1a'))
        c.rect(0, H-28*mm, W, 28*mm, fill=1, stroke=0)
        c.setFillColor(hx('#e8327a'))
        c.rect(0, H-2.5*mm, W, 2.5*mm, fill=1, stroke=0)
        c.setFillColor(hx('#e8327a'))
        c.rect(0, H-28*mm-2.5*mm, W, 2.5*mm, fill=1, stroke=0)
 
        c.drawImage(logo_img, ml, H-28*mm+5*mm, width=17*mm, height=17*mm, mask='auto')
 
        c.setFillColor(hx('#ffffff'))
        c.setFont(FB, 13)
        c.drawString(ml+22*mm, H-28*mm+17*mm,
                     f'MOSFERICS — {list_name.upper()} PRICE LIST')
        c.setFillColor(hx('#888888'))
        c.setFont(F, 8)
        c.drawString(ml+22*mm, H-28*mm+10*mm,
            f'Trade Price List  |  2025/26  |  All prices ex. VAT  |  Page {pg_num} of {total}')
        today = datetime.date.today().strftime('%d %B %Y')
        c.setFillColor(hx('#888888'))
        c.setFont(F, 7)
        c.drawRightString(W-mr, H-28*mm+17*mm, f'Generated {today}')
        c.setFillColor(hx('#e8327a'))
        c.setFont(FB, 7)
        c.drawRightString(W-mr, H-28*mm+10.5*mm, 'Prices subject to change without notice')
 
        col_y = H-28*mm-2.5*mm-8*mm
        c.setFillColor(hx('#2a2a2a'))
        c.rect(0, col_y, W, 8*mm, fill=1, stroke=0)
        c.setFillColor(hx('#888888'))
        c.setFont(FB, 6.5)
        c.drawString(sku_x+2, col_y+2.8*mm, 'SKU')
        c.drawString(name_x, col_y+2.8*mm, 'PRODUCT DESCRIPTION')
        c.drawCentredString(price_x+price_w/2, col_y+2.8*mm, 'PRICE (EX. VAT)')
 
        cur_y = col_y
 
        for it in pg_items:
            if it[0] == 'cat':
                cur_y -= CH
                c.setFillColor(hx('#333333'))
                c.rect(0, cur_y, W, CH, fill=1, stroke=0)
                c.setFillColor(hx('#e8327a'))
                c.rect(ml, cur_y, 3, CH, fill=1, stroke=0)
                c.setFillColor(hx('#ffffff'))
                c.setFont(FB, 8)
                c.drawString(ml+7, cur_y+2.5*mm, it[1].upper())
            else:
                _, sku, title, price, lines, rh = it
                cur_y -= rh
                c.setFillColor(hx('#ffffff' if row_idx%2==0 else '#f7f7f7'))
                c.rect(0, cur_y, W, rh, fill=1, stroke=0)
                mid = cur_y + rh/2 - 1.5
 
                c.setFillColor(hx('#e8327a'))
                c.setFont(FB, 6.5)
                c.drawString(sku_x+2, mid, sku)
 
                c.setFillColor(hx('#1a1a1a'))
                c.setFont(F, FS)
                bh = len(lines)*LH
                ty = cur_y + (rh+bh)/2 - LH + 0.5*mm
                for i, line in enumerate(lines):
                    c.drawString(name_x, ty - i*LH, line)
 
                c.setFillColor(hx('#1a1a1a'))
                c.setFont(FB, 7.5)
                c.drawCentredString(price_x+price_w/2, mid, f'£{price:.2f}')
 
                c.setStrokeColor(hx('#dddddd'))
                c.setLineWidth(0.3)
                c.line(0, cur_y, W, cur_y)
                row_idx += 1
 
        c.setStrokeColor(hx('#dddddd'))
        c.setLineWidth(0.5)
        c.line(0, cur_y, W, cur_y)
 
        if is_last:
            ny = cur_y - 5*mm
            c.setFillColor(hx('#f2f2f2'))
            c.roundRect(ml, ny-NH, W-ml-mr, NH, 2, fill=1, stroke=0)
            c.setFillColor(hx('#e8327a'))
            c.roundRect(ml, ny-NH, 3, NH, 1.5, fill=1, stroke=0)
            c.setFillColor(hx('#1a1a1a'))
            c.setFont(FB, 6.5)
            c.drawString(ml+6, ny-3.5*mm, 'PRICING NOTE')
            c.setFillColor(hx('#444444'))
            c.setFont(F, 6.5)
            c.drawString(ml+6, ny-7*mm,
                'All prices are per unit/pack as listed, exclusive of VAT. '
                'Prices are subject to change — contact your account manager before ordering.')
 
        c.setFillColor(hx('#1a1a1a'))
        c.rect(0, 0, W, FTR, fill=1, stroke=0)
        c.setFillColor(hx('#e8327a'))
        c.rect(0, FTR-0.6*mm, W, 0.6*mm, fill=1, stroke=0)
        c.setFillColor(hx('#888888'))
        c.setFont(F, 7)
        c.drawString(ml, 5.5*mm,
            'sales@mosferics.com   |   +44 7581 180675   |   www.shop.mosferics.com')
        c.setFillColor(hx('#444444'))
        c.drawRightString(W-mr, 5.5*mm,
            'Mosferics Bar & Restaurant Equipment  |  Trade Only  |  Prices Ex. VAT')
 
        c.save()
 
    writer = PdfWriter()
    for path in page_files:
        for page in PdfReader(path).pages:
            writer.add_page(page)
        try: os.unlink(path)
        except: pass
    try: os.unlink(tmp0)
    except: pass
 
    with open(output_path, 'wb') as f:
        writer.write(f)
 
# ── GUI ────────────────────────────────────────────────────────────────────
def main():
    # Check tkinter is available — Homebrew Python on Mac often lacks it
    try:
        import tkinter as tk
        from tkinter import filedialog, messagebox, ttk
    except ImportError:
        import subprocess, sys
        # Try to show an OS-level error dialog
        msg = (
            "Mosferics Price List Generator could not start.\n\n"
            "The required 'tkinter' module is missing from your Python installation.\n\n"
            "Fix: open Terminal and run:\n"
            "  conda install tk\n\n"
            "Or reinstall using your original Python (miniconda/anaconda)."
        )
        if sys.platform == 'darwin':
            subprocess.run(['osascript', '-e',
                f'display dialog "{msg}" buttons {{"OK"}} default button "OK" '
                f'with title "Mosferics — Missing Dependency"'])
        else:
            print(msg)
        sys.exit(1)
 
    # Check for updates first — 5 second timeout so it never hangs
    if check_for_update():
        sys.exit(0)
 
    root = tk.Tk()
    root.withdraw()
 
    excel_path = filedialog.askopenfilename(
        title='Select Shopify product export',
        filetypes=[('Excel files', '*.xlsx *.xls'), ('All files', '*.*')]
    )
    if not excel_path:
        return
 
    win = tk.Toplevel()
    win.title(f'Mosferics Price List Generator  v{VERSION}')
    win.resizable(False, False)
    win.configure(bg='#1a1a1a')
    win.grab_set()
 
    style = ttk.Style(win)
    style.theme_use('default')
    style.configure('Pink.TButton',
        background='#e8327a', foreground='white',
        font=('Helvetica', 10, 'bold'), padding=(14, 6),
        relief='flat', borderwidth=0)
    style.map('Pink.TButton',
        background=[('active', '#c5205c'), ('pressed', '#a01548')],
        foreground=[('active', 'white'), ('pressed', 'white')])
    style.configure('Grey.TButton',
        background='#444444', foreground='white',
        font=('Helvetica', 10), padding=(14, 6),
        relief='flat', borderwidth=0)
    style.map('Grey.TButton',
        background=[('active', '#555555'), ('pressed', '#333333')],
        foreground=[('active', 'white'), ('pressed', 'white')])
    style.configure('Dark.TRadiobutton',
        background='#1a1a1a', foreground='white',
        font=('Helvetica', 10))
    style.map('Dark.TRadiobutton',
        background=[('active', '#1a1a1a')],
        foreground=[('active', 'white')])
 
    tk.Label(win,
        text='Which price list would you like to generate?',
        font=('Helvetica', 11, 'bold'), fg='white', bg='#1a1a1a',
        wraplength=300, pady=14).pack(padx=20)
 
    selected = tk.StringVar(value=LIST_COLUMNS[0])
    for col in LIST_COLUMNS:
        ttk.Radiobutton(win, text=col, variable=selected,
                        value=col, style='Dark.TRadiobutton').pack(anchor='w', padx=36, pady=2)
 
    confirmed = {'go': False}
 
    def on_generate():
        confirmed['go'] = True
        win.destroy()
 
    btn_frame = tk.Frame(win, bg='#1a1a1a')
    btn_frame.pack(pady=18)
    ttk.Button(btn_frame, text='Generate PDF',
               command=on_generate, style='Pink.TButton').pack(side='left', padx=8)
    ttk.Button(btn_frame, text='Cancel',
               command=win.destroy, style='Grey.TButton').pack(side='left', padx=8)
 
    win.update_idletasks()
    w, h = 360, 280
    x = (win.winfo_screenwidth() - w) // 2
    y = (win.winfo_screenheight() - h) // 2
    win.geometry(f'{w}x{h}+{x}+{y}')
 
    win.wait_window()
    if not confirmed['go']:
        return
 
    list_name = selected.get()
 
    try:
        grouped = load_products(excel_path, list_name)
    except Exception as e:
        messagebox.showerror('Error reading file', str(e))
        return
 
    total     = sum(len(v) for v in grouped.values())
    cat_lines = '\n'.join(f'  \u2022 {k}  ({len(v)} products)' for k, v in grouped.items())
 
    if not messagebox.askyesno('Ready to generate',
        f'Found {total} products in {len(grouped)} categories for "{list_name}":\n\n'
        f'{cat_lines}\n\nGenerate PDF now?'):
        return
 
    # Incrementing filename
    safe      = list_name.replace(' ', '_').replace('&', 'and')
    downloads = Path.home() / 'Downloads'
    downloads.mkdir(exist_ok=True)
    base = downloads / f'Mosferics_{safe}_Price_List.pdf'
    if base.exists():
        counter = 1
        while True:
            candidate = downloads / f'Mosferics_{safe}_Price_List ({counter}).pdf'
            if not candidate.exists():
                base = candidate
                break
            counter += 1
    out = str(base)
 
    try:
        generate_pdf(grouped, list_name, out)
    except Exception as e:
        messagebox.showerror('Error generating PDF', str(e))
        return
 
    messagebox.showinfo('Done!', f'Saved to:\n{out}')
 
    import subprocess, platform
    try:
        if platform.system() == 'Darwin':
            subprocess.run(['open', out])
        elif platform.system() == 'Windows':
            os.startfile(out)
        else:
            subprocess.run(['xdg-open', out])
    except Exception:
        pass
 
if __name__ == '__main__':
    main()
